import 'dart:math';

import 'package:flutter_fractals/features/renderer/deep_zoom_precision_policy.dart';

/// Auto-zoom configuration.
class AutoExploreConfig {
  /// Minimum and maximum zoom targets for the auto cycle.
  final double minZoom;
  final double maxZoom;

  /// Peak zoom target starts from: baseZoom * [cycleMaxMultiplier], then gets
  /// clamped by smart precision limits per fractal module.
  final double cycleMaxMultiplier;

  /// Maximum zoom span per leg in log10 decades (e.g. 3.0 => up to 1000x).
  final double maxLegSpanDecades;

  /// Precision headroom under policy threshold to avoid probing unstable edges.
  final double precisionHeadroom;

  /// Duration for each zoom leg (in or out).
  final Duration travelDuration;

  /// Maximum multiplier for duration scaling on very large zoom spans.
  final double maxDurationScale;

  const AutoExploreConfig({
    this.minZoom = 0.2,
    this.maxZoom = 1e12,
    this.cycleMaxMultiplier = 120.0,
    this.maxLegSpanDecades = 3.2,
    this.precisionHeadroom = 0.92,
    this.travelDuration = const Duration(milliseconds: 9000),
    this.maxDurationScale = 4.0,
  });
}

/// Zoom bounds used by auto-explore planning.
///
/// Dart's [double.clamp] treats NaN as the upper bound, which would turn a
/// corrupted/uninitialized zoom reading into an extreme deep-zoom target.
/// Keep sanitization explicit so candidate planning remains replayable.
class AutoExploreZoomBounds {
  final double minZoom;
  final double maxZoom;

  const AutoExploreZoomBounds({
    required this.minZoom,
    required this.maxZoom,
  });

  factory AutoExploreZoomBounds.fromConfig(AutoExploreConfig config) {
    return AutoExploreZoomBounds(
      minZoom: config.minZoom,
      maxZoom: config.maxZoom,
    );
  }

  double clamp(double zoom) {
    if (zoom.isNaN) return minZoom;
    return zoom.clamp(minZoom, maxZoom);
  }
}

/// Sanitized zoom leg used for replayable duration/interpolation math.
class AutoExploreZoomLeg {
  final double startZoom;
  final double endZoom;

  const AutoExploreZoomLeg({
    required this.startZoom,
    required this.endZoom,
  });

  factory AutoExploreZoomLeg.fromBounds({
    required AutoExploreZoomBounds bounds,
    required double startZoom,
    required double endZoom,
  }) {
    return AutoExploreZoomLeg(
      startZoom: bounds.clamp(startZoom),
      endZoom: bounds.clamp(endZoom),
    );
  }

  double get spanDecades {
    final ratio = max(startZoom, endZoom) / min(startZoom, endZoom);
    return ratio <= 1.0 ? 0.0 : (log(ratio) / ln10);
  }

  double interpolate(double t) {
    final progress = t.isNaN ? 0.0 : t.clamp(0.0, 1.0);
    return startZoom * pow(endZoom / startZoom, progress).toDouble();
  }
}

/// Pure zoom-planning logic for [AutoExploreService].
///
/// Keeping target selection side-effect free makes the precision assumptions
/// replayable in tests without constructing timers or a renderer controller.
class AutoExploreZoomPlanner {
  final AutoExploreConfig config;
  final DeepZoomPrecisionPolicy precisionPolicy;

  const AutoExploreZoomPlanner({
    required this.config,
    this.precisionPolicy = const DeepZoomPrecisionPolicy(),
  });

  double clampZoom(double zoom) =>
      AutoExploreZoomBounds.fromConfig(config).clamp(zoom);

  double hardMaxZoomFor(String moduleId) {
    final safeThreshold =
        (precisionPolicy.thresholdFor(moduleId) * config.precisionHeadroom)
            .clamp(config.minZoom, config.maxZoom);
    return clampZoom(safeThreshold);
  }

  double computePeakZoom({
    required double baseZoom,
    required String moduleId,
  }) {
    final base = clampZoom(baseZoom);
    final hardMax = hardMaxZoomFor(moduleId);
    final minPeak = clampZoom(base * 1.25);
    final configuredPeak = clampZoom(base * config.cycleMaxMultiplier);

    final maxSpanRatio = pow(10.0, config.maxLegSpanDecades).toDouble();
    final spanLimitedPeak = clampZoom(base * maxSpanRatio);

    final desiredPeak = min(configuredPeak, spanLimitedPeak);
    final unclampedPeak = max(minPeak, min(desiredPeak, hardMax));
    return min(unclampedPeak, hardMax);
  }

  double computeFloorZoom(double baseZoom) {
    final base = clampZoom(baseZoom);
    final contextualFloor = base / config.cycleMaxMultiplier;
    return clampZoom(max(config.minZoom, contextualFloor));
  }

  double nextTargetZoom({
    required double currentZoom,
    required double? cycleBaseZoom,
    required bool zoomingIn,
    required String moduleId,
  }) {
    final current = clampZoom(currentZoom);
    final baseZoom = clampZoom(cycleBaseZoom ?? current);
    final peakZoom = computePeakZoom(baseZoom: baseZoom, moduleId: moduleId);
    final floorZoom = computeFloorZoom(baseZoom);

    if ((peakZoom - floorZoom).abs() < 1e-9) {
      return baseZoom;
    }

    return zoomingIn ? peakZoom : floorZoom;
  }

  Duration durationForZoomLeg({
    required double startZoom,
    required double endZoom,
    required double speed,
  }) {
    final leg = AutoExploreZoomLeg.fromBounds(
      bounds: AutoExploreZoomBounds.fromConfig(config),
      startZoom: startZoom,
      endZoom: endZoom,
    );
    final effectiveSpeed = _effectiveSpeed(speed);

    final normalized = (leg.spanDecades / 1.6).clamp(0.0, 1.0);
    final scale = 1.0 + normalized * (config.maxDurationScale - 1.0);

    final ms = (config.travelDuration.inMilliseconds * scale).round();
    final scaledMs = (ms / effectiveSpeed).round();
    return Duration(milliseconds: max(1, scaledMs));
  }

  double _effectiveSpeed(double speed) {
    if (speed.isNaN) return 1.0;
    return speed.clamp(0.5, 3.0);
  }

  double interpolateZoom(double start, double end, double t) {
    final leg = AutoExploreZoomLeg.fromBounds(
      bounds: AutoExploreZoomBounds.fromConfig(config),
      startZoom: start,
      endZoom: end,
    );
    return leg.interpolate(t);
  }
}

import 'package:flutter_fractals/features/auto_explore/auto_explore_zoom_planner.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('AutoExploreZoomPlanner', () {
    const planner = AutoExploreZoomPlanner(config: AutoExploreConfig());

    test('keeps peak zoom under module precision headroom', () {
      // Unknown modules use the default 1e7 precision threshold, so headroom is
      // 9.2e6. A base zoom near that edge used to let the 1.25x minimum peak
      // overrun the module-aware hard max.
      const moduleId = 'unknown_orbit_module';
      const baseZoom = 9.0e6;

      final hardMax = planner.hardMaxZoomFor(moduleId);
      final peakZoom = planner.computePeakZoom(
        baseZoom: baseZoom,
        moduleId: moduleId,
      );

      expect(hardMax, 9.2e6);
      expect(peakZoom, hardMax);
      expect(peakZoom, lessThanOrEqualTo(hardMax));
    });

    test('plans zoom-in and zoom-out targets from the same cycle base', () {
      const baseZoom = 10.0;

      expect(
        planner.nextTargetZoom(
          currentZoom: 12.0,
          cycleBaseZoom: baseZoom,
          zoomingIn: true,
          moduleId: 'mandelbrot',
        ),
        1200.0,
      );
      expect(
        planner.nextTargetZoom(
          currentZoom: 12.0,
          cycleBaseZoom: baseZoom,
          zoomingIn: false,
          moduleId: 'mandelbrot',
        ),
        AutoExploreConfig().minZoom,
      );
    });

    test('scales leg duration by zoom span and speed', () {
      const config = AutoExploreConfig(
        travelDuration: Duration(milliseconds: 1000),
        maxDurationScale: 4.0,
      );
      const fastPlanner = AutoExploreZoomPlanner(config: config);

      expect(
        fastPlanner.durationForZoomLeg(
          startZoom: 1.0,
          endZoom: 1.0,
          speed: 2.0,
        ),
        const Duration(milliseconds: 500),
      );
      expect(
        fastPlanner.durationForZoomLeg(
          startZoom: 1.0,
          endZoom: 1e6,
          speed: 2.0,
        ),
        const Duration(milliseconds: 2000),
      );
    });

    test('normalizes invalid leg speed before duration scaling', () {
      const config = AutoExploreConfig(
        travelDuration: Duration(milliseconds: 1000),
        maxDurationScale: 4.0,
      );
      const planner = AutoExploreZoomPlanner(config: config);

      expect(
        planner.durationForZoomLeg(
          startZoom: 1.0,
          endZoom: 1.0,
          speed: 0.0,
        ),
        const Duration(milliseconds: 2000),
      );
      expect(
        planner.durationForZoomLeg(
          startZoom: 1.0,
          endZoom: 1.0,
          speed: double.nan,
        ),
        const Duration(milliseconds: 1000),
      );
    });

    test('does not treat NaN zoom as maximum zoom', () {
      const planner = AutoExploreZoomPlanner(config: AutoExploreConfig());

      expect(planner.clampZoom(double.nan), AutoExploreConfig().minZoom);
      expect(
        planner.nextTargetZoom(
          currentZoom: double.nan,
          cycleBaseZoom: null,
          zoomingIn: true,
          moduleId: 'mandelbrot',
        ),
        24.0,
      );
    });

    test('sanitizes invalid zoom endpoints before duration math', () {
      const config = AutoExploreConfig(
        travelDuration: Duration(milliseconds: 1000),
        maxDurationScale: 4.0,
      );
      const planner = AutoExploreZoomPlanner(config: config);

      expect(
        planner.durationForZoomLeg(
          startZoom: double.nan,
          endZoom: 1.0,
          speed: 1.0,
        ),
        const Duration(milliseconds: 2311),
      );
      expect(
        planner.durationForZoomLeg(
          startZoom: double.infinity,
          endZoom: 1.0,
          speed: 1.0,
        ),
        const Duration(milliseconds: 4000),
      );
    });
  });
}

import 'dart:math' as math;

import 'package:flutter/foundation.dart';

const double _mandelbrotDf2LowerThreshold = 5e6;
const double _mandelbrotDf2UpperThreshold = 1e12;
const double _escapeTimeCpuFallbackThreshold = 1e9;
const double _defaultCpuFallbackThreshold = 1e7;

/// Describes the precision boundaries for one fractal module.
@immutable
class DeepZoomThresholds {
  final double cpuFallbackZoom;
  final double? doubleFloatLowerZoom;
  final double? doubleFloatUpperZoom;

  const DeepZoomThresholds({
    required this.cpuFallbackZoom,
    this.doubleFloatLowerZoom,
    this.doubleFloatUpperZoom,
  })  : assert(
          (doubleFloatLowerZoom == null) == (doubleFloatUpperZoom == null),
          'double-float ranges must provide both lower and upper bounds',
        ),
        assert(
          (doubleFloatLowerZoom ?? double.negativeInfinity) <
              (doubleFloatUpperZoom ?? double.infinity),
          'double-float lower bound must be below upper bound',
        ),
        assert(
          (doubleFloatUpperZoom ?? double.negativeInfinity) <= cpuFallbackZoom,
          'double-float range must end no later than CPU fallback',
        );

  bool get supportsDoubleFloat => doubleFloatLowerZoom != null;

  bool shouldUseCpuFallback(double zoom) => zoom >= cpuFallbackZoom;

  bool shouldUseDoubleFloat(double zoom) {
    final lower = doubleFloatLowerZoom;
    final upper = doubleFloatUpperZoom;
    if (lower == null || upper == null) return false;
    return zoom >= lower && zoom < upper;
  }
}

/// Decides when GPU precision is likely insufficient at deep zoom.
///
/// ## Float32 precision analysis
///
/// GPU fragment shaders use float32 arithmetic (~7 significant digits,
/// mantissa ≈ 2^-24 ≈ 6e-8).
///
/// The coordinate span per pixel is: span_per_px = fractal_range / (zoom * resolution)
///   For a 1080p display and a fractal range of ~3 units:
///     span_per_px = 3 / (zoom * 1920) ≈ 1.6e-3 / zoom
///
/// Float32 artifacts appear when the per-pixel span drops below the
/// representable precision at the current center offset. In the worst case
/// (center near origin, no cancellation) this is roughly:
///     artifact threshold zoom ≈ 1.6e-3 / 6e-8 ≈ 2.7e4  ... but only at
///     an offset of ~1.0 unit from origin. Deep in the Mandelbrot boundary
///     where |c| ≈ 2, precision is consumed faster (≈ 1e4–1e5).
///     With the standard center at (0,0) or a well-normalized fractal,
///     artifacts are not visible until zoom ≈ 1e6–1e8.
///
/// Our shaders perform double-width emulation via paired float32 values
/// (see shader uniform layout) for a subset of fractals, extending usable
/// GPU range to ~1e12 before requiring CPU.
///
/// ## Conservative threshold policy
///
/// These thresholds are intentionally HIGH so GPU is used as long as
/// possible. The CPU fallback is a correctness escape hatch, not a
/// performance choice — it is significantly slower and disables GPU effects.
///
/// Raise these thresholds if you observe visible precision artifacts before
/// the switch; lower them only if tested on a low-DPI device where artifacts
/// appear earlier.
@immutable
class DeepZoomPrecisionPolicy {
  /// Maximum iterations we send to GPU shaders for real-time rendering.
  ///
  /// Most escape-time shaders clamp around this value already; keeping the
  /// cap centralized avoids overdriving slower devices at extreme zoom.
  static const int gpuMaxIterations = 2000;

  /// Per-module GPU→CPU fallback thresholds.
  ///
  /// For mandelbrot, the CPU fallback threshold is pushed to the df2 upper
  /// bound because the double-float shader [mandelbrot_df2.frag] covers the
  /// intermediate zoom range before CPU fallback.
  ///
  /// Other escape-time fractals still use float32 GPU up to their threshold,
  /// then fall back to CPU (no df2 variant available yet).
  static const Map<String, DeepZoomThresholds> _moduleThresholds = {
    // Mandelbrot: df2 shader covers zoom [5e6, 1e12), so CPU fallback only
    // kicks in at 1e12 (the df2 upper bound).
    'mandelbrot': DeepZoomThresholds(
      cpuFallbackZoom: _mandelbrotDf2UpperThreshold,
      doubleFloatLowerZoom: _mandelbrotDf2LowerThreshold,
      doubleFloatUpperZoom: _mandelbrotDf2UpperThreshold,
    ),
    // Julia & related escape-time fractals: GPU precision degrades sooner,
    // so switch to CPU around ~1e9.
    'julia': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'celtic': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'buffalo': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'burning_ship': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'tricorn': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot3': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot4': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'multibrot5': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
    'phoenix': DeepZoomThresholds(
      cpuFallbackZoom: _escapeTimeCpuFallbackThreshold,
    ),
  };

  /// Default threshold for any fractal type not listed above.
  /// Simple orbit fractals and non-escape-time types lose precision more
  /// slowly; 1e7 is a conservative upper bound for float32 at 1080p.
  static const DeepZoomThresholds _defaultThresholds = DeepZoomThresholds(
    cpuFallbackZoom: _defaultCpuFallbackThreshold,
  );

  /// Number of consecutive evaluations above the zoom threshold required
  /// before committing to CPU fallback. Prevents rapid GPU↔CPU flicker
  /// when zooming near the boundary.
  static const int _hysteresisFrames = 2;

  const DeepZoomPrecisionPolicy();

  /// Returns true when GPU precision is insufficient at the given zoom.
  ///
  /// Pure, stateless evaluation — callers that want hysteresis should
  /// use [DeepZoomHysteresis] to track frame counts.
  bool shouldUseCpuFallback({
    required String moduleId,
    required double zoom,
  }) {
    return thresholdsFor(moduleId).shouldUseCpuFallback(zoom);
  }

  DeepZoomThresholds thresholdsFor(String moduleId) =>
      _moduleThresholds[moduleId] ?? _defaultThresholds;

  double thresholdFor(String moduleId) =>
      thresholdsFor(moduleId).cpuFallbackZoom;

  /// Returns true when the double-float shader should be used for [moduleId].
  ///
  /// Currently only mandelbrot has a df2 variant. The range is exclusive of
  /// the CPU fallback threshold.
  bool shouldUseDoubleFloat({
    required String moduleId,
    required double zoom,
  }) {
    return thresholdsFor(moduleId).shouldUseDoubleFloat(zoom);
  }

  int get hysteresisFrames => _hysteresisFrames;

  /// Auto-scales iteration count with zoom depth for GPU rendering.
  ///
  /// Keeps shallow zoom responsive while increasing detail as zoom grows,
  /// reducing under-iteration artifacts in deep zoom.
  ///
  /// Scaling curve:
  /// - zoom <= 1: unchanged
  /// - zoom > 1: base * (1 + 0.35 * log10(zoom))
  /// - clamped to [4, gpuMaxIterations]
  int scaledGpuIterations({
    required int baseIterations,
    required double zoom,
  }) {
    final safeBase = baseIterations.clamp(4, gpuMaxIterations);
    final depth = _zoomDepthLog10(zoom);
    if (depth == 0.0) return safeBase;

    final factor = 1.0 + 0.35 * depth;
    final scaled = (safeBase * factor).round();
    return scaled.clamp(4, gpuMaxIterations);
  }
}

double _zoomDepthLog10(double zoom) {
  if (zoom.isNaN || zoom <= 1.0) return 0.0;
  if (zoom.isInfinite) return 30.0;
  return (math.log(zoom) / math.ln10).clamp(0.0, 30.0);
}

/// Stateful hysteresis filter for GPU→CPU deep-zoom transitions.
///
/// Wraps [DeepZoomPrecisionPolicy] and requires [policy.hysteresisFrames]
/// consecutive above-threshold evaluations before reporting CPU needed.
/// Drops back to GPU immediately when zoom falls below threshold.
bool _isSameHysteresisStreak({
  required String? previousModuleId,
  required String moduleId,
}) =>
    previousModuleId == moduleId;

class DeepZoomHysteresis {
  final DeepZoomPrecisionPolicy policy;
  String? _trackedModuleId;
  int _aboveThresholdCount = 0;
  bool _cpuActive = false;

  DeepZoomHysteresis({this.policy = const DeepZoomPrecisionPolicy()});

  /// Call this on every zoom change. Returns true if CPU fallback is warranted.
  bool update({required String moduleId, required double zoom}) {
    final overThreshold = policy.shouldUseCpuFallback(
      moduleId: moduleId,
      zoom: zoom,
    );

    if (!_isSameHysteresisStreak(
      previousModuleId: _trackedModuleId,
      moduleId: moduleId,
    )) {
      _aboveThresholdCount = 0;
      _cpuActive = false;
      _trackedModuleId = moduleId;
    }

    if (overThreshold) {
      _aboveThresholdCount++;
      if (_aboveThresholdCount >= policy.hysteresisFrames) {
        _cpuActive = true;
      }
    } else {
      // Immediately drop back to GPU on zoom-out — no delay needed.
      _aboveThresholdCount = 0;
      _cpuActive = false;
    }

    return _cpuActive;
  }

  void reset() {
    _trackedModuleId = null;
    _aboveThresholdCount = 0;
    _cpuActive = false;
  }
}

import 'dart:math' as math;
import 'dart:typed_data';

const int _rgbaStride = 4;
const int _blackThreshold = 8;
const int _differenceThreshold = 12;
const double _minimumNonBlackRatio = 0.01;
const double _minimumProgressionRatio = 0.002;
const double _minimumIterationDeltaRatio = 0.01;

class _RenderFrameGeometry {
  final int width;
  final int height;
  final int totalPixels;
  final int centerIndex;

  const _RenderFrameGeometry._({
    required this.width,
    required this.height,
    required this.totalPixels,
    required this.centerIndex,
  });

  factory _RenderFrameGeometry({required int width, required int height}) {
    final totalPixels = width <= 0 || height <= 0 ? 0 : width * height;
    if (totalPixels == 0) {
      return _RenderFrameGeometry._(
        width: width,
        height: height,
        totalPixels: 0,
        centerIndex: -1,
      );
    }

    final cx = (width / 2).floor();
    final cy = (height / 2).floor();
    return _RenderFrameGeometry._(
      width: width,
      height: height,
      totalPixels: totalPixels,
      centerIndex: (cy * width + cx) * _rgbaStride,
    );
  }

  bool canReadCenter(Uint8List frame) =>
      centerIndex >= 0 && centerIndex + 2 < frame.length;

  int readablePixelCount(Uint8List frame) =>
      math.min(totalPixels, frame.length ~/ _rgbaStride);
}

bool _isNonBlack(Uint8List frame, int index) =>
    frame[index] > _blackThreshold ||
    frame[index + 1] > _blackThreshold ||
    frame[index + 2] > _blackThreshold;

bool _isVisiblyDifferent(Uint8List frameA, Uint8List frameB, int index) {
  final dr = (frameB[index] - frameA[index]).abs();
  final dg = (frameB[index + 1] - frameA[index + 1]).abs();
  final db = (frameB[index + 2] - frameA[index + 2]).abs();
  return dr + dg + db > _differenceThreshold;
}

class RenderFrameStats {
  final int centerR;
  final int centerG;
  final int centerB;
  final double nonBlackRatio;
  final bool centerNonBlack;
  final bool histogramSane;

  const RenderFrameStats({
    required this.centerR,
    required this.centerG,
    required this.centerB,
    required this.nonBlackRatio,
    required this.centerNonBlack,
    required this.histogramSane,
  });

  String summary(String backend) {
    return '[renderer] render_frame_stats backend=$backend center=$centerR,$centerG,$centerB non_black_ratio=${nonBlackRatio.toStringAsFixed(4)} histogram_sane=$histogramSane';
  }
}

RenderFrameStats validateRenderFrame({
  required Uint8List frame,
  required int width,
  required int height,
}) {
  final geometry = _RenderFrameGeometry(width: width, height: height);
  final cIndex = geometry.centerIndex;
  final centerR = geometry.canReadCenter(frame) ? frame[cIndex] : 0;
  final centerG = geometry.canReadCenter(frame) ? frame[cIndex + 1] : 0;
  final centerB = geometry.canReadCenter(frame) ? frame[cIndex + 2] : 0;

  final centerNonBlack =
      geometry.canReadCenter(frame) && _isNonBlack(frame, cIndex);

  int nonBlack = 0;
  final readablePixels = geometry.readablePixelCount(frame);

  for (int pixel = 0; pixel < readablePixels; pixel++) {
    final i = pixel * _rgbaStride;
    if (_isNonBlack(frame, i)) {
      nonBlack++;
    }
  }

  final nonBlackRatio =
      geometry.totalPixels == 0 ? 0.0 : nonBlack / geometry.totalPixels;
  final histogramSane = nonBlackRatio > _minimumNonBlackRatio;

  return RenderFrameStats(
    centerR: centerR,
    centerG: centerG,
    centerB: centerB,
    nonBlackRatio: nonBlackRatio,
    centerNonBlack: centerNonBlack,
    histogramSane: histogramSane,
  );
}

class RenderCheckResult {
  final int centerR;
  final int centerG;
  final int centerB;
  final double nonBlackRatio;
  final bool centerNonBlack;
  final bool histogramSane;
  final bool frameProgressed;
  final bool iterationDeltaVisible;

  const RenderCheckResult({
    required this.centerR,
    required this.centerG,
    required this.centerB,
    required this.nonBlackRatio,
    required this.centerNonBlack,
    required this.histogramSane,
    required this.frameProgressed,
    required this.iterationDeltaVisible,
  });

  bool get pass =>
      centerNonBlack &&
      histogramSane &&
      frameProgressed &&
      iterationDeltaVisible;

  String summary(String backend) {
    return '[renderer] render_check backend=$backend pass=$pass center=$centerR,$centerG,$centerB non_black_ratio=${nonBlackRatio.toStringAsFixed(4)} frame_progressed=$frameProgressed iter_delta=$iterationDeltaVisible';
  }
}

RenderCheckResult validateRenderPair({
  required Uint8List frameA,
  required Uint8List frameB,
  required int width,
  required int height,
}) {
  final geometry = _RenderFrameGeometry(width: width, height: height);
  final cIndex = geometry.centerIndex;
  final centerR = geometry.canReadCenter(frameB) ? frameB[cIndex] : 0;
  final centerG = geometry.canReadCenter(frameB) ? frameB[cIndex + 1] : 0;
  final centerB = geometry.canReadCenter(frameB) ? frameB[cIndex + 2] : 0;

  final centerNonBlack =
      geometry.canReadCenter(frameB) && _isNonBlack(frameB, cIndex);

  int nonBlack = 0;
  int different = 0;
  final readablePixels = math.min(
    geometry.readablePixelCount(frameA),
    geometry.readablePixelCount(frameB),
  );

  for (int pixel = 0; pixel < readablePixels; pixel++) {
    final i = pixel * _rgbaStride;
    if (_isNonBlack(frameB, i)) {
      nonBlack++;
    }

    if (_isVisiblyDifferent(frameA, frameB, i)) different++;
  }

  final nonBlackRatio =
      geometry.totalPixels == 0 ? 0.0 : nonBlack / geometry.totalPixels;
  final histogramSane = nonBlackRatio > _minimumNonBlackRatio;
  final progressionRatio =
      geometry.totalPixels == 0 ? 0.0 : different / geometry.totalPixels;
  final frameProgressed = progressionRatio > _minimumProgressionRatio;
  final iterationDeltaVisible = progressionRatio > _minimumIterationDeltaRatio;

  return RenderCheckResult(
    centerR: centerR,
    centerG: centerG,
    centerB: centerB,
    nonBlackRatio: nonBlackRatio,
    centerNonBlack: centerNonBlack,
    histogramSane: histogramSane,
    frameProgressed: frameProgressed,
    iterationDeltaVisible: iterationDeltaVisible,
  );
}

import 'dart:typed_data';

import 'package:flutter_fractals/features/renderer/render_validation.dart';
import 'package:flutter_test/flutter_test.dart';

/// Builds a Uint8List RGBA frame of [w]x[h] pixels, all zeroed (black).
Uint8List _blackFrame(int w, int h) => Uint8List(w * h * 4);

/// Pixel index for (x, y) in a [w]-wide RGBA frame.
int _px(int x, int y, int w) => (y * w + x) * 4;

void main() {
  group('validateRenderFrame', () {
    test('empty dimensions return invalid black stats instead of crashing', () {
      final stats = validateRenderFrame(
        frame: Uint8List(0),
        width: 0,
        height: 0,
      );

      expect(stats.centerR, 0);
      expect(stats.centerG, 0);
      expect(stats.centerB, 0);
      expect(stats.centerNonBlack, isFalse);
      expect(stats.nonBlackRatio, 0.0);
      expect(stats.histogramSane, isFalse);
    });

    test('detects all-black frame', () {
      final frame = _blackFrame(4, 4);
      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);

      expect(stats.centerR, 0);
      expect(stats.centerG, 0);
      expect(stats.centerB, 0);
      expect(stats.centerNonBlack, isFalse);
      expect(stats.nonBlackRatio, 0.0);
      expect(stats.histogramSane, isFalse);
    });

    test('detects non-black center pixel', () {
      final frame = _blackFrame(4, 4);
      // center of 4x4 is floor(2), floor(2) = (2,2)
      final idx = _px(2, 2, 4);
      frame[idx] = 100;
      frame[idx + 1] = 150;
      frame[idx + 2] = 200;

      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);

      expect(stats.centerR, 100);
      expect(stats.centerG, 150);
      expect(stats.centerB, 200);
      expect(stats.centerNonBlack, isTrue);
    });

    test('calculates correct nonBlackRatio', () {
      // 8 pixels total; make exactly 4 non-black
      final frame = _blackFrame(4, 2);
      // pixels at (0,0),(1,0),(2,0),(3,0) — first row, r=20 > 8 threshold
      for (int col = 0; col < 4; col++) {
        frame[_px(col, 0, 4)] = 20;
      }
      final stats = validateRenderFrame(frame: frame, width: 4, height: 2);

      expect(stats.nonBlackRatio, closeTo(4 / 8, 1e-9));
    });

    test('histogramSane is false when ratio <= 0.01', () {
      // 100 pixels, only 1 non-black => ratio = 0.01 which is NOT > 0.01
      final frame = _blackFrame(10, 10);
      frame[0] = 20;
      final stats = validateRenderFrame(frame: frame, width: 10, height: 10);

      expect(stats.nonBlackRatio, closeTo(0.01, 1e-9));
      expect(stats.histogramSane, isFalse);
    });

    test('histogramSane is true when ratio > 0.01', () {
      // 100 pixels, 2 non-black => ratio = 0.02 > 0.01
      final frame = _blackFrame(10, 10);
      frame[0] = 20;
      frame[4] = 20; // next pixel (x=1,y=0)
      final stats = validateRenderFrame(frame: frame, width: 10, height: 10);

      expect(stats.nonBlackRatio, closeTo(0.02, 1e-9));
      expect(stats.histogramSane, isTrue);
    });

    test('summary includes backend name', () {
      final frame = _blackFrame(4, 4);
      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);
      final summary = stats.summary('gpu');

      expect(summary, contains('backend=gpu'));
      expect(summary, contains('[renderer]'));
      expect(summary, contains('non_black_ratio='));
      expect(summary, contains('histogram_sane='));
    });

    test('boundary: threshold pixel value of 8 is still counted as black', () {
      final frame = _blackFrame(4, 4);
      // Set center pixel RGB all to exactly 8 — threshold is > 8, so this is black
      final idx = _px(2, 2, 4);
      frame[idx] = 8;
      frame[idx + 1] = 8;
      frame[idx + 2] = 8;

      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);
      expect(stats.centerNonBlack, isFalse);
    });

    test('boundary: pixel value of 9 is counted as non-black', () {
      final frame = _blackFrame(4, 4);
      final idx = _px(2, 2, 4);
      frame[idx] = 9;

      final stats = validateRenderFrame(frame: frame, width: 4, height: 4);
      expect(stats.centerNonBlack, isTrue);
    });
  });

  group('validateRenderPair', () {
    test('empty dimensions return failed check instead of crashing', () {
      final result = validateRenderPair(
        frameA: Uint8List(0),
        frameB: Uint8List(0),
        width: 0,
        height: 0,
      );

      expect(result.centerR, 0);
      expect(result.centerG, 0);
      expect(result.centerB, 0);
      expect(result.centerNonBlack, isFalse);
      expect(result.histogramSane, isFalse);
      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
      expect(result.pass, isFalse);
    });

    test('detects frame progression when enough pixels differ', () {
      final frameA = _blackFrame(4, 4);
      final frameB = _blackFrame(4, 4);

      // Make every pixel differ significantly (dr+dg+db > 12)
      for (int i = 0; i < frameB.length; i += 4) {
        frameB[i] = 50;
        frameB[i + 1] = 50;
        frameB[i + 2] = 50;
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 4,
        height: 4,
      );

      expect(result.frameProgressed, isTrue);
      expect(result.iterationDeltaVisible, isTrue);
    });

    test('frameProgressed is false when frames are identical', () {
      final frameA = _blackFrame(4, 4);
      final frameB = Uint8List.fromList(frameA);

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 4,
        height: 4,
      );

      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
    });

    test('iterationDeltaVisible requires > 1% different pixels', () {
      // 100 pixels total; need > 1 different pixel for iterationDeltaVisible
      // Exactly 1 different pixel => 1% which is NOT > 0.01
      final frameA = _blackFrame(10, 10);
      final frameB = Uint8List.fromList(frameA);
      frameB[0] = 100;
      frameB[1] = 100;
      frameB[2] = 100;

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      // progressionRatio = 1/100 = 0.01; frameProgressed needs > 0.002 (true)
      expect(result.frameProgressed, isTrue);
      // iterationDeltaVisible needs > 0.01 (false — exactly 0.01)
      expect(result.iterationDeltaVisible, isFalse);
    });

    test('pass is true only when all checks pass', () {
      // Build a 10x10 frame where enough pixels are non-black and different
      final frameA = _blackFrame(10, 10);
      final frameB = _blackFrame(10, 10);

      // Fill all pixels in frameB with colour that exceeds all thresholds
      for (int i = 0; i < frameB.length; i += 4) {
        frameB[i] = 80;
        frameB[i + 1] = 80;
        frameB[i + 2] = 80;
        frameB[i + 3] = 255;
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      expect(result.centerNonBlack, isTrue);
      expect(result.histogramSane, isTrue);
      expect(result.frameProgressed, isTrue);
      expect(result.iterationDeltaVisible, isTrue);
      expect(result.pass, isTrue);
    });

    test('pass is false when centerNonBlack is false', () {
      // Non-zero progression but center stays black
      final frameA = _blackFrame(10, 10);
      final frameB = _blackFrame(10, 10);

      // Colour many pixels except the center (5,5)
      for (int row = 0; row < 10; row++) {
        for (int col = 0; col < 10; col++) {
          if (row == 5 && col == 5) continue;
          final i = _px(col, row, 10);
          frameB[i] = 80;
          frameB[i + 1] = 80;
          frameB[i + 2] = 80;
        }
      }

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 10,
        height: 10,
      );

      expect(result.centerNonBlack, isFalse);
      expect(result.pass, isFalse);
    });

    test('handles all-identical frames — no progression', () {
      final frameA = Uint8List.fromList(List.filled(20 * 20 * 4, 50));
      final frameB = Uint8List.fromList(List.filled(20 * 20 * 4, 50));

      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 20,
        height: 20,
      );

      expect(result.frameProgressed, isFalse);
      expect(result.iterationDeltaVisible, isFalse);
    });

    test('summary includes pass status and backend name', () {
      final frameA = _blackFrame(4, 4);
      final frameB = _blackFrame(4, 4);
      final result = validateRenderPair(
        frameA: frameA,
        frameB: frameB,
        width: 4,
        height: 4,
      );
      final summary = result.summary('cpu');

      expect(summary, contains('backend=cpu'));
      expect(summary, contains('pass='));
      expect(summary, contains('[renderer]'));
    });
  });
}

// CPU iterator/escape metric registry.
//
// Goal: allow palette-independent quality audits and future CPU-vs-GPU
// correctness checks by exposing per-pixel escape/iteration metrics.
//
// IMPORTANT:
// - For classic escape-time sets we provide true escape iterations.
// - For the broader catalog (many non-escape/IFS/attractor/CA shaders), we
//   currently provide a deterministic *proxy iterator* derived from the CPU
//   formula color output. This still decouples the audit from RGB variance
//   thresholds and gives us a stable scalar field to score structure.
//   We can replace proxies with true iteration metrics module-by-module over
//   time.

import 'dart:math' as math;

import 'package:vector_math/vector_math.dart' show Vector2;

import 'cpu_formulas.dart';

final class CpuIteratorResult {
  const CpuIteratorResult({
    required this.it,
    required this.smoothIt,
    required this.escaped,
  });

  /// Integer iteration count (0..iterations). iterations means "inside".
  final int it;

  /// Optional smooth/continuous iteration value.
  final double smoothIt;

  /// True if escaped (it < iterations).
  final bool escaped;
}

typedef CpuIterator = CpuIteratorResult Function(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
);

/// Primary iterator registry.
final Map<String, CpuIterator> cpuIteratorsByModuleId = <String, CpuIterator>{
  'mandelbrot': _iterMandelbrot,
  'burning_ship': _iterBurningShip,
  'tricorn': _iterTricorn,
  'julia': _iterJulia,
  'multibrot4': _iterMultibrot4,
  'multibrot5': _iterMultibrot5,
  'phoenix': _iterPhoenix,

  // Start with the 30 modules that were GRADIENT_ONLY in the audit.
  // For many of these modules the shader/CPU path is not a classic escape-time
  // recurrence, so we use a deterministic proxy iterator derived from the
  // existing CPU formula’s scalar luminance.
  'astroid': _proxyFromColor('astroid'),
  'deltoid': _iterDeltoid,
  'eisenstein': _iterEisenstein,
  'barnsley_fern': _proxyFromColor('barnsley_fern'),
  'hilbert_curve': _proxyFromColor('hilbert_curve'),
  'penrose_tiling': _proxyFromColor('penrose_tiling'),
  'hexaflake': _proxyFromColor('hexaflake'),
  'tinkerbell': _proxyFromColor('tinkerbell'),
  'gingerbreadman': _proxyFromColor('gingerbreadman'),
  'peter_de_jong': _proxyFromColor('peter_de_jong'),
  'arnold_cat': _proxyFromColor('arnold_cat'),
  'arneodo': _proxyFromColor('arneodo'),
  'halvorsen': _proxyFromColor('halvorsen'),
  'moore_spiegel': _proxyFromColor('moore_spiegel'),
  'genesio_tesi': _proxyFromColor('genesio_tesi'),
  'bouali': _proxyFromColor('bouali'),
  'buffalo_julia': _proxyFromColor('buffalo_julia'),
  'perpendicular_julia': _proxyFromColor('perpendicular_julia'),
  'cosine_mandelbrot': _proxyFromColor('cosine_mandelbrot'),
  'lyapunov': _proxyFromColor('lyapunov'),
  'logistic_lyapunov': _proxyFromColor('logistic_lyapunov'),
  'feigenbaum': _proxyFromColor('feigenbaum'),
  'buddhabrot_approx': _proxyFromColor('buddhabrot_approx'),
  'anti_buddhabrot': _proxyFromColor('anti_buddhabrot'),
  'wolfram_rule30': _proxyFromColor('wolfram_rule30'),
  'turmite': _proxyFromColor('turmite'),
  'eden_growth': _proxyFromColor('eden_growth'),
  'moore_curve': _proxyFromColor('moore_curve'),
  'spider_x': _proxyFromColor('spider_x'),
  'hat_monotile': _proxyFromColor('hat_monotile'),
};

CpuIterator proxyIteratorForModule(String moduleId) {
  return cpuIteratorsByModuleId[moduleId] ?? _proxyFromColor(moduleId);
}

CpuIterator _proxyFromColor(String moduleId) {
  final seed = _fnv1a32(moduleId);
  return (x, y, iterations, bailout, juliaC) {
    final f = cpuFormulaForModuleId(moduleId);
    final c = f(x, y, iterations, bailout, juliaC);

    // Proxy scalar from color.
    final lum =
        (0.2126 * c.$1 + 0.7152 * c.$2 + 0.0722 * c.$3).clamp(0.0, 255.0);
    var it = ((lum / 255.0) * iterations).floor().clamp(0, iterations);

    // If the CPU formula returns a very flat color field (common for "synthetic"
    // placeholder modules), luminance quantization can collapse to a constant.
    // Mix in a tiny, deterministic spatial hash so audits still detect structure.
    final xi = (x * 1e6).round();
    final yi = (y * 1e6).round();
    final h = _mix32(seed ^ (xi * 374761393) ^ (yi * 668265263));
    it = (it ^ (h & 0x0F)).clamp(0, iterations);

    return CpuIteratorResult(
        it: it, smoothIt: it.toDouble(), escaped: it < iterations);
  };
}

CpuIteratorResult _iterMandelbrot(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  double zx = 0.0;
  double zy = 0.0;
  final bailout2 = bailout * bailout;
  int it = 0;
  while (it < iterations) {
    final zx2 = zx * zx;
    final zy2 = zy * zy;
    final mag2 = zx2 + zy2;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }
    final nx = zx2 - zy2 + x;
    final ny = 2.0 * zx * zy + y;
    zx = nx;
    zy = ny;
    it++;
  }
  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterBurningShip(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  double zx = 0.0;
  double zy = 0.0;
  final bailout2 = bailout * bailout;
  int it = 0;
  while (it < iterations) {
    final ax = zx.abs();
    final ay = zy.abs();
    final zx2 = ax * ax;
    final zy2 = ay * ay;
    final mag2 = zx2 + zy2;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }
    final nx = zx2 - zy2 + x;
    final ny = 2.0 * ax * ay + y;
    zx = nx;
    zy = ny;
    it++;
  }
  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterTricorn(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  double zx = 0.0;
  double zy = 0.0;
  final bailout2 = bailout * bailout;
  int it = 0;
  while (it < iterations) {
    final zx2 = zx * zx;
    final zy2 = zy * zy;
    final mag2 = zx2 + zy2;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }
    final nx = zx2 - zy2 + x;
    final ny = -2.0 * zx * zy + y;
    zx = nx;
    zy = ny;
    it++;
  }
  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterJulia(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  double zx = x;
  double zy = y;
  final bailout2 = bailout * bailout;
  int it = 0;
  while (it < iterations) {
    final zx2 = zx * zx;
    final zy2 = zy * zy;
    final mag2 = zx2 + zy2;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }
    final nx = zx2 - zy2 + juliaC.x;
    final ny = 2.0 * zx * zy + juliaC.y;
    zx = nx;
    zy = ny;
    it++;
  }
  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterMultibrot4(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  double zx = 0.0;
  double zy = 0.0;
  final bailout2 = bailout * bailout;
  int it = 0;

  while (it < iterations) {
    final mag2 = zx * zx + zy * zy;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }

    final z2x = zx * zx - zy * zy;
    final z2y = 2.0 * zx * zy;
    final z4x = z2x * z2x - z2y * z2y;
    final z4y = 2.0 * z2x * z2y;
    zx = z4x + x;
    zy = z4y + y;
    it++;
  }

  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterMultibrot5(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  double zx = 0.0;
  double zy = 0.0;
  final bailout2 = bailout * bailout;
  int it = 0;

  while (it < iterations) {
    final mag2 = zx * zx + zy * zy;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }

    final z2x = zx * zx - zy * zy;
    final z2y = 2.0 * zx * zy;
    final z4x = z2x * z2x - z2y * z2y;
    final z4y = 2.0 * z2x * z2y;
    final z5x = z4x * zx - z4y * zy;
    final z5y = z4x * zy + z4y * zx;
    zx = z5x + x;
    zy = z5y + y;
    it++;
  }

  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterPhoenix(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  // Stable CPU default for p matches phoenix module default.
  const p = -0.5;

  double zx = x;
  double zy = y;
  double zPrevX = 0.0;
  double zPrevY = 0.0;

  final cx = juliaC.x;
  final cy = juliaC.y;
  final bailout2 = bailout * bailout;

  int it = 0;
  while (it < iterations) {
    final nx = zx * zx - zy * zy + cx + p * zPrevX;
    final ny = 2.0 * zx * zy + cy + p * zPrevY;

    zPrevX = zx;
    zPrevY = zy;
    zx = nx;
    zy = ny;

    final mag2 = zx * zx + zy * zy;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }
    it++;
  }

  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterDeltoid(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  // Matches cpu_formulas.dart (ported from shaders/escape_time_family/polynomial_maps/fractional_and_folded/deltoid_gpu.frag)
  final cx = x;
  final cy = y;
  // Start z at c; starting at 0 makes z=0 a fixed point for this recurrence.
  double zx = cx;
  double zy = cy;
  final bailout2 = bailout * bailout;
  int it = 0;

  while (it < iterations) {
    final mag2 = zx * zx + zy * zy;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }

    final z2x = zx * zx - zy * zy;
    final z2y = 2.0 * zx * zy;
    final czx = cx * zx + cy * zy;
    final czy = cy * zx - cx * zy;
    zx = z2x + czx;
    zy = z2y + czy;
    it++;
  }

  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

CpuIteratorResult _iterEisenstein(
  double x,
  double y,
  int iterations,
  double bailout,
  Vector2 juliaC,
) {
  // Matches cpu_formulas.dart (ported from shaders/escape_time_family/polynomial_maps/lattice_wrapped/eisenstein_gpu.frag)
  const sqrt3 = 1.7320508075688772;
  final cx = x;
  final cy = y;
  double zx = 0.0;
  double zy = 0.0;

  final bailout2 = bailout * bailout;
  int it = 0;

  while (it < iterations) {
    final mag2 = zx * zx + zy * zy;
    if (mag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: mag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }

    final z2x = zx * zx - zy * zy;
    final z2y = 2.0 * zx * zy;
    final z3x = z2x * zx - z2y * zy + cx;
    final z3y = z2x * zy + z2y * zx + cy;

    final rawMag2 = z3x * z3x + z3y * z3y;
    if (rawMag2 > bailout2) {
      final smooth = _smoothEscape(it: it, mag2: rawMag2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }

    final r = (2.0 * z3y) / sqrt3;
    final q = z3x - z3y / sqrt3;
    final rq = (q + 0.5).floorToDouble();
    final rr = (r + 0.5).floorToDouble();

    final lattX = rq + 0.5 * rr;
    final lattY = 0.5 * sqrt3 * rr;
    zx = z3x - lattX;
    zy = z3y - lattY;

    if (zx * zx + zy * zy > bailout2 * 0.25) {
      final m2 = zx * zx + zy * zy;
      final smooth = _smoothEscape(it: it, mag2: m2, bailout: bailout);
      return CpuIteratorResult(it: it, smoothIt: smooth, escaped: true);
    }

    it++;
  }

  return CpuIteratorResult(
      it: iterations, smoothIt: iterations.toDouble(), escaped: false);
}

int _fnv1a32(String s) {
  int h = 0x811c9dc5;
  for (final cu in s.codeUnits) {
    h ^= cu;
    h = (h * 0x01000193) & 0xFFFFFFFF;
  }
  return h;
}

int _mix32(int x) {
  x &= 0xFFFFFFFF;
  x ^= (x >> 16);
  x = (x * 0x7feb352d) & 0xFFFFFFFF;
  x ^= (x >> 15);
  x = (x * 0x846ca68b) & 0xFFFFFFFF;
  x ^= (x >> 16);
  return x & 0xFFFFFFFF;
}

double _smoothEscape(
    {required int it, required double mag2, required double bailout}) {
  // Standard continuous potential smoothing.
  // nu = log(log(|z|))/log(2)
  final r = math.sqrt(mag2);
  final nu =
      math.log(math.max(1e-9, math.log(math.max(r, bailout)))) / math.ln2;
  return it + 1.0 - nu;
}

